INSERT INTO words (word, category_id, position, tag, zh, en, example_en, example_zh, synonyms) VALUES
  ('here', 'op', 76, 'OP', '这里；在此处', 'in or to this place', 'Put the basket here by the door.', '把篮子放在门边这里。', '[{"w":"forward","def":"forward: 相关的动作或关系词","vs":"与 here 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"forward\" / \"here\" 的替换练习"},{"w":"near","def":"near: 可帮助扩展句型的基础词","vs":"与 here 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"near\" / \"here\" 的替换练习"},{"w":"now","def":"now: 同一组 Basic English 操作词","vs":"与 here 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"now\" / \"here\" 的替换练习"}]'),
  ('near', 'op', 77, 'OP', '近；靠近', 'not far away in place or time', 'The school is near the river.', '学校在河流附近。', '[{"w":"here","def":"here: 相关的动作或关系词","vs":"与 near 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"here\" / \"near\" 的替换练习"},{"w":"now","def":"now: 可帮助扩展句型的基础词","vs":"与 near 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"now\" / \"near\" 的替换练习"},{"w":"out","def":"out: 同一组 Basic English 操作词","vs":"与 near 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"out\" / \"near\" 的替换练习"}]'),
  ('now', 'op', 78, 'OP', '现在；此刻', 'at the present time', 'Now we can start the lesson.', '现在我们可以开始上课。', '[{"w":"near","def":"near: 相关的动作或关系词","vs":"与 now 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"near\" / \"now\" 的替换练习"},{"w":"out","def":"out: 可帮助扩展句型的基础词","vs":"与 now 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"out\" / \"now\" 的替换练习"},{"w":"still","def":"still: 同一组 Basic English 操作词","vs":"与 now 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"still\" / \"now\" 的替换练习"}]'),
  ('out', 'op', 79, 'OP', '在外；向外；出来', 'away from the inside or not at home', 'Take the wet clothes out into the sun.', '把湿衣服拿到外面晒太阳。', '[{"w":"now","def":"now: 相关的动作或关系词","vs":"与 out 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"now\" / \"out\" 的替换练习"},{"w":"still","def":"still: 可帮助扩展句型的基础词","vs":"与 out 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"still\" / \"out\" 的替换练习"},{"w":"then","def":"then: 同一组 Basic English 操作词","vs":"与 out 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"then\" / \"out\" 的替换练习"}]'),
  ('still', 'op', 80, 'OP', '仍然；静止的；安静的', 'continuing, quiet, or without movement', 'The water is still after the wind stops.', '风停后，水面平静。', '[{"w":"out","def":"out: 相关的动作或关系词","vs":"与 still 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"out\" / \"still\" 的替换练习"},{"w":"then","def":"then: 可帮助扩展句型的基础词","vs":"与 still 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"then\" / \"still\" 的替换练习"},{"w":"there","def":"there: 同一组 Basic English 操作词","vs":"与 still 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"there\" / \"still\" 的替换练习"}]');
